import{_ as h,y as i,a,o as c,ag as g,D as u}from"./chunks/framework.C2qfZH9T.js";const v=JSON.parse('{"title":"Thương mại điện tử dành cho nhiều người thuê","description":"","frontmatter":{},"headers":[],"relativePath":"multi-tenant-ecommerce/introduction.md","filePath":"multi-tenant-ecommerce/introduction.md","lastUpdated":1775320633000}'),o={name:"multi-tenant-ecommerce/introduction.md"};function e(r,n,p,m,l,d){const t=i("ImagePopup");return c(),a("div",null,[n[0]||(n[0]=g('<h1 id="thuong-mai-đien-tu-danh-cho-nhieu-nguoi-thue" tabindex="-1">Thương mại điện tử dành cho nhiều người thuê <a class="header-anchor" href="#thuong-mai-đien-tu-danh-cho-nhieu-nguoi-thue" aria-label="Permalink to &quot;Thương mại điện tử dành cho nhiều người thuê&quot;">​</a></h1><p><a href="https://bagisto.com/en/laravel-multi-tenant-saas/" target="_blank" rel="noreferrer">Thương mại điện tử nhiều người thuê</a> tại VNS cho phép các doanh nghiệp xây dựng nền tảng thị trường dựa trên SaaS, nơi nhiều nhà cung cấp hoặc người bán có thể tạo và quản lý các cửa hàng riêng lẻ của riêng họ trong một hệ thống duy nhất.</p><p>Mỗi người thuê (người bán) có một mặt tiền cửa hàng chuyên dụng với toàn quyền kiểm soát các sản phẩm, danh mục, đơn đặt hàng và khách hàng, trong khi chủ sở hữu nền tảng quản lý cơ sở hạ tầng tổng thể, đăng ký và mô hình doanh thu. Thiết lập này giúp giảm chi phí hoạt động cho người bán vì họ không cần đầu tư vào việc phát triển hoặc lưu trữ thương mại điện tử riêng biệt.</p><h3 id="quan-ly-quan-tri-vien-cap-cao" tabindex="-1">Quản lý quản trị viên cấp cao <a class="header-anchor" href="#quan-ly-quan-tri-vien-cap-cao" aria-label="Permalink to &quot;Quản lý quản trị viên cấp cao&quot;">​</a></h3><p>Vị trí Quản trị viên cấp cao là người có thẩm quyền cao nhất trong trung tâm mua sắm SaaS, chịu trách nhiệm giám sát người thuê, nhân viên và toàn bộ hoạt động của nền tảng.</p><p>Vai trò này bao gồm quản lý người bán (người thuê), giao vai trò cho nhân viên (đại lý) và đảm bảo mọi thứ hoạt động tốt với nhau trong hệ thống.</p><p>Quản trị viên cấp cao thiết lập những sản phẩm hiển thị, quản lý kênh và thiết kế chủ đề để duy trì giao diện và thương hiệu nhất quán cho tất cả các cửa hàng thuê.</p><p>Họ cũng quản lý các trang CMS, gửi email và quản lý cài đặt chung để đảm bảo giao tiếp rõ ràng và quản trị nền tảng phù hợp.</p><h3 id="tquan-ly-thue-nha" tabindex="-1">TQuản lý thuê nhà <a class="header-anchor" href="#tquan-ly-thue-nha" aria-label="Permalink to &quot;TQuản lý thuê nhà&quot;">​</a></h3><p>Quản lý người thuê trong SaaS giúp người thuê dễ dàng đăng ký và nhanh chóng tạo cửa hàng trực tuyến bằng cách điền thông tin đăng nhập, cá nhân và tổ chức của họ.</p><p>Sau khi họ đăng ký, mặt tiền cửa hàng của người thuê sẽ được thiết lập tự động nên họ có thể bắt đầu bán hàng ngay lập tức mà không gặp bất kỳ khó khăn kỹ thuật nào.</p><p>Sử dụng Bảng quản trị người thuê, người thuê có thể quản lý sản phẩm, danh mục, thuộc tính, khách hàng, v.v. thông qua giao diện thân thiện với người dùng tương tự như VNS.</p><p>Người thuê cũng có thể quản lý đơn đặt hàng bằng cách lập hóa đơn, thiết lập lô hàng và sử dụng các tùy chọn menu khác để vận hành cửa hàng của mình một cách hiệu quả.</p><p>Bản đồ tên ### C</p><p>Bản đồ CName cho phép người thuê kết nối tên miền của riêng họ với tên miền phụ do SaaS tạo ra, giúp xây dựng thương hiệu chuyên nghiệp.</p><p>Khi người thuê đăng ký, một tên miền phụ mặc định như <strong>username.rootdomain.com</strong> sẽ được tạo. Với CNAME, tên miền thực của họ có thể được chuyển hướng đến tên miền phụ này.</p><p>Điều này giúp khách hàng dễ dàng tìm thấy cửa hàng và giữ được hình ảnh trực tuyến đáng tin cậy, nhất quán.</p><p>Ánh xạ được thiết lập thông qua nhà cung cấp DNS của đối tượng thuê và SaaS bởi Quản trị viên cấp cao và không cần bất kỳ plugin bổ sung nào.</p>',18)),u(t,{src:"/images/multi-tenant-ecommerce/multi-tenant.webp",alt:"Super Admin Login"})])}const q=h(o,[["render",e]]);export{v as __pageData,q as default};
